static void rotarDerecha(int[] v, int k) {
    if (v == null || v.length < 2) return;
    k %= v.length;
    if (k < 0) k += v.length;
    invertir(v, 0, v.length - 1);
    invertir(v, 0, k - 1);
    invertir(v, k, v.length - 1);
}

static void invertir(int[] v, int i, int j) {
    while (i < j) {
        int tmp = v[i];
        v[i++] = v[j];
        v[j--] = tmp;
    }
}

